import{_ as o,o as a,c as t,a0 as r}from"./chunks/framework.SERXgfZn.js";const h=JSON.parse('{"title":"Privacy Policy","description":"","frontmatter":{"sidebar":false,"aside":false,"prev":false,"next":false},"headers":[],"relativePath":"en/privacy-policy.md","filePath":"en/privacy-policy.md"}'),i={name:"en/privacy-policy.md"};function n(s,e,l,c,d,p){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="privacy-policy" tabindex="-1">Privacy Policy <a class="header-anchor" href="#privacy-policy" aria-label="Permalink to &quot;Privacy Policy&quot;">​</a></h1><p><strong>Last updated: June 30, 2026</strong></p><p>Effective date: July 1, 2026</p><p>Welcome to NovaAPI (&quot;we,&quot; &quot;us,&quot; or the &quot;Platform&quot;). We understand how critically important data privacy is to developers and enterprise customers. As a platform providing global LLM aggregation and routing, as well as specific vertical API and Agent services, we are committed to protecting your information with the highest standards of security.</p><p>This Privacy Policy is intended to explain how we collect, use, store, and delete your personal information when we provide our products or services, and to inform you of the personal information rights you enjoy.</p><p><strong>Before you begin using our website and Services, please be sure to read and understand this Privacy Policy carefully, and make sure you fully understand and agree to it before you start using them.</strong></p><h3 id="_1-what-information-do-we-collect" tabindex="-1">1. What Information Do We Collect? <a class="header-anchor" href="#_1-what-information-do-we-collect" aria-label="Permalink to &quot;1. What Information Do We Collect?&quot;">​</a></h3><p>To provide secure and stable billing and services, we <strong>collect only the minimum information necessary to keep the Services running</strong>:</p><ul><li><p><strong>Account and Billing Information</strong></p><ul><li><p><strong>Basic credentials</strong>: Your registered email address and account password (stored using hashed encryption).</p></li><li><p><strong>Billing information</strong>: When you top up, payment processing is completed by secure third-party merchants of record (such as Stripe, Lemon Squeezy, Paddle, etc.). <strong>We do not directly collect or store sensitive financial data such as your full credit card number.</strong></p></li></ul></li><li><p><strong>API Usage Metadata</strong></p><ul><li>To enable accurate pay-as-you-go billing, we record the <strong>metadata</strong> of each API call: request time, request IP address, the name of the target model invoked (e.g., <code>deepseek-v4-pro</code>), and the number of input/output Tokens consumed.</li></ul></li><li><p><strong>System Technical Information</strong></p><ul><li>Device information (browser type, operating system) and error logs used for security defense and system optimization.</li></ul></li></ul><h3 id="_2-how-do-we-use-your-information" tabindex="-1">2. How Do We Use Your Information? <a class="header-anchor" href="#_2-how-do-we-use-your-information" aria-label="Permalink to &quot;2. How Do We Use Your Information?&quot;">​</a></h3><p>The Platform collects your personal information for the following purposes. When we intend to use the collected information for other purposes not stated in this Policy, we will seek your consent and authorization in advance.</p><ol><li><p>To provide, maintain, and improve our products or services;</p></li><li><p>To send you important notices regarding system security, changes to products or services, and similar matters;</p></li><li><p>To activate or verify products or services;</p></li><li><p>To promote and introduce products to you where permitted by laws and regulations; you have the right to opt out;</p></li><li><p>To provide you with personalized products, services, or a personalized user experience;</p></li><li><p>To conduct internal audits, data analysis, and research to improve our products and services; and your rights regarding automated individual decision-making and user profiling;</p></li><li><p>To protect the information technology security of our products, services, and users;</p></li><li><p>To comply with and enforce applicable legal requirements or relevant industry standards. For example, where the law requires real-name verification, the collected information, including bank card numbers, is used only for real-name verification purposes and not for any other purpose;</p></li><li><p>Other purposes with your permission. If you have any objection to the purposes of data processing, or wish us to stop one or more ways of using your data, please contact our customer support team.</p></li></ol><h3 id="_3-how-do-we-share-information" tabindex="-1">3. How Do We Share Information? <a class="header-anchor" href="#_3-how-do-we-share-information" aria-label="Permalink to &quot;3. How Do We Share Information?&quot;">​</a></h3><p>We <strong>never sell or rent</strong> any of your personal data. We share information with trusted third parties only in the following necessary scenarios:</p><ul><li><p><strong>Model providers: to receive the user content and technical information necessary to complete inference.</strong> They will process the data in accordance with their respective privacy policies.</p></li><li><p><strong>Cloud and infrastructure providers</strong>: to provide servers, databases, object storage, CDN, DDoS protection, monitoring, logging, email, and customer support. They are bound by strict Data Processing Agreements (DPAs).</p></li><li><p><strong>Government, regulatory, and law enforcement authorities</strong>: disclosed only where there is a lawful basis, appropriate authority, and a reasonable scope of request; where permitted by law, we will review, narrow, or challenge overly broad requests.</p></li></ul><h3 id="_4-data-security-and-storage" tabindex="-1">4. Data Security and Storage <a class="header-anchor" href="#_4-data-security-and-storage" aria-label="Permalink to &quot;4. Data Security and Storage&quot;">​</a></h3><ul><li><p><strong>Transmission encryption</strong>: All traffic in and out of NovaAPI is end-to-end encrypted (HTTPS) using strong-standard TLS/SSL.</p></li><li><p><strong>Key protection</strong>: The <code>sk-</code> API Keys you generate and upstream channel keys are stored in the database using industry-leading asymmetric encryption.</p></li><li><p><strong>No absolute security</strong>: Although we adopt top-tier commercial protection measures, transmission over the internet cannot be guaranteed to be 100% absolutely secure. Please be sure to safeguard your own API Keys and avoid hard-coding them into public code repositories where they could be leaked.</p></li></ul><h3 id="_5-data-retention-period" tabindex="-1">5. Data Retention Period <a class="header-anchor" href="#_5-data-retention-period" aria-label="Permalink to &quot;5. Data Retention Period&quot;">​</a></h3><ul><li><p><strong>Account data</strong>: As long as your account remains active, we will retain your registration information.</p></li><li><p><strong>Log data</strong>: To handle billing disputes and analyze abnormal calls, API call metadata (limited to time, model, and Token count) is <strong>retained for a maximum of 90 days</strong>, after which it is automatically rolling-deleted or fully anonymized.</p></li><li><p><strong>Deletion upon deregistration</strong>: When you proactively apply to deregister your account, we will permanently erase your personally identifying information from the active database within 30 days.</p></li></ul><h3 id="_6-your-rights" tabindex="-1">6. Your Rights <a class="header-anchor" href="#_6-your-rights" aria-label="Permalink to &quot;6. Your Rights&quot;">​</a></h3><p>Depending on the laws of your location and the role we play, you may have the right to:</p><ul><li><p>Be informed of, access, and obtain a copy of your personal information;</p></li><li><p>Correct or supplement inaccurate information;</p></li><li><p>Delete personal information or deregister your account;</p></li><li><p>Restrict or object to specific processing;</p></li><li><p>Withdraw consent;</p></li><li><p>Obtain structured, commonly used, and machine-readable data, or request its transfer;</p></li><li><p>Understand the basics of automated decision-making, and, where provided by law, refuse significant decisions made solely by automated decision-making;</p></li><li><p>Unsubscribe from marketing information;</p></li><li><p>Raise complaints or appeals regarding privacy processing, or complain to a regulatory authority.</p></li></ul><p>To exercise the above rights, please contact us using the contact information at the end of this Policy.</p><h3 id="_7-cookies-and-similar-technologies" tabindex="-1">7. Cookies and Similar Technologies <a class="header-anchor" href="#_7-cookies-and-similar-technologies" aria-label="Permalink to &quot;7. Cookies and Similar Technologies&quot;">​</a></h3><p>We may use:</p><ul><li><p>Login and session Cookies, to maintain login status and enable secure logout;</p></li><li><p>Security Cookies, to prevent bots, DDoS, fraud, and abnormal logins;</p></li><li><p>Preference Cookies, to remember language and interface settings;</p></li><li><p>Analytics Cookies, to understand website performance and usage, enabled only where permitted by applicable law or with your consent.</p></li></ul><p>We do not use Cookies for the purpose of selling personal information, and we support users in managing non-essential Cookies.</p><h3 id="_8-cross-border-data-transfers" tabindex="-1">8. Cross-Border Data Transfers <a class="header-anchor" href="#_8-cross-border-data-transfers" aria-label="Permalink to &quot;8. Cross-Border Data Transfers&quot;">​</a></h3><p>Your information may be transferred to servers outside your country or region for processing. In such cases, we will take appropriate measures to ensure that your information receives protection consistent with this Privacy Policy. We will conduct cross-border data transfers in compliance with applicable legal requirements.</p><h3 id="_9-updates-to-this-policy" tabindex="-1">9. Updates to This Policy <a class="header-anchor" href="#_9-updates-to-this-policy" aria-label="Permalink to &quot;9. Updates to This Policy&quot;">​</a></h3><p>We may update this Policy due to changes in services, providers, technology, or laws. Material changes will be reasonably notified in advance via email, the console, or the website; where required by law, we will obtain consent again. The latest update and effective date will be displayed at the top of the page. Continuing to use NovaAPI indicates that you accept the updated privacy terms.</p><h3 id="_10-contact-us" tabindex="-1">10. Contact Us <a class="header-anchor" href="#_10-contact-us" aria-label="Permalink to &quot;10. Contact Us&quot;">​</a></h3><p>If you have any questions, comments, or requests regarding this Privacy Policy, please contact us through the following means:</p><p>Email: <a href="mailto:support@novaapis.com" target="_blank" rel="noreferrer">support@novaapis.com</a></p><p>We will respond within 15 business days after receiving your request.</p>',35)])])}const m=o(i,[["render",n]]);export{h as __pageData,m as default};
